import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"F18: 合理估值與決策綜合判斷 - 投資研究員 (finance-investment-researcher) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F18_合理估值與決策綜合判斷_投資研究員.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F18_合理估值與決策綜合判斷_投資研究員.md"}'),l={name:"審計報告庫/財務審計/8064_東捷/20260429/F18_合理估值與決策綜合判斷_投資研究員.md"};function n(o,t,s,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f18-合理估值與決策綜合判斷-投資研究員-finance-investment-researcher-審計報告" tabindex="-1">F18: 合理估值與決策綜合判斷 - 投資研究員 (finance-investment-researcher) 審計報告 <a class="header-anchor" href="#f18-合理估值與決策綜合判斷-投資研究員-finance-investment-researcher-審計報告" aria-label="Permalink to &quot;F18: 合理估值與決策綜合判斷 - 投資研究員 (finance-investment-researcher) 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>綜合潛在風險、未來願景與籌碼面，公司當前的合理估值落於何種區間？本益比河流圖是否具備安全邊際？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li>結論：B(持平)，安全邊際為負。估值區間47-60元(19x PE)，距現價-37~-50%。戰術：60元以下分批佈局。</li><li>數據時效：根據截至2026年4月29日最新股價（94.9元）及2025年報</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li>2025 EPS 1.36元→PE 69.8x(同業30-35x)</li><li>歷史PE 15-22x，現溢價3-4.6倍</li><li>外資4月淨賣超6,379張；融資10,616張</li><li>診斷：當前股價已超前反映2026年轉型預期，安全邊際為負。PE河流圖超越+2SD上限，處歷史極端溢價區間，風險報酬極不對稱。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-風險壓力測試-risk-stress-test" tabindex="-1">1. 風險壓力測試 (Risk Stress Test) <a class="header-anchor" href="#_1-風險壓力測試-risk-stress-test" aria-label="Permalink to &quot;1. 風險壓力測試 (Risk Stress Test)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：輕度壓力(營收-10%)→EPS 0.5-0.6元，PE 158-190x，股價修正40%+。重度壓力(面板衰退+漢錸缺口)→營收跌破BEP，回測20-30元。</li><li><strong>見解</strong>：高度不對稱風險結構——上行有限(EPS 5→19x PE=95元持平)，下行動輒40-70%。</li></ul><h3 id="_2-評價位階對位-valuation-anchoring" tabindex="-1">2. 評價位階對位 (Valuation Anchoring) <a class="header-anchor" href="#_2-評價位階對位-valuation-anchoring" aria-label="Permalink to &quot;2. 評價位階對位 (Valuation Anchoring)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：<table tabindex="0"><thead><tr><th>估值模型</th><th>合理價(元)</th><th>基於2026E EPS</th><th>距現價空間</th></tr></thead><tbody><tr><td>歷史PE中樞19x(保守)</td><td>47.5</td><td>2.50(剔除信用迴轉+正常化)</td><td>-50%</td></tr><tr><td>歷史PE上緣22x+成長溢價</td><td>60.0</td><td>3.16(法人共識下限)</td><td>-37%</td></tr><tr><td>歷史PE上緣22x(樂觀)</td><td>95.0</td><td>4.32(法人共識中值)</td><td>+0%</td></tr><tr><td>P/B 2.5x(設備業均值)</td><td>48.9</td><td>淨值19.54</td><td>-48%</td></tr><tr><td>P/B 4.86x(現行)</td><td>94.9</td><td>已鎖定</td><td>0%</td></tr></tbody></table></li><li><strong>見解</strong>：三階段折現→內在價值47-60元。現價94.9元超出上限57%，全數仰賴EPS達4.32元以上的超級情境。若此情境落空，股價下檔極深。</li></ul><h3 id="_3-最終執行建議-final-action-plan" tabindex="-1">3. 最終執行建議 (Final Action Plan) <a class="header-anchor" href="#_3-最終執行建議-final-action-plan" aria-label="Permalink to &quot;3. 最終執行建議 (Final Action Plan)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：評級B(持平)。買進60元以下(37%安全邊際)，理想47-50元(50%安全邊際)。停損47元。</li><li><strong>見解</strong>：東捷處轉型收穫期但股價已超前反映。95元為低點以來+158%漲幅，景氣尚未確認復甦。建議等待20-40%回檔，遵守深度價值紀律。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>風險一：景氣轉折未確立，股價已搶跑</strong> 營收+10.2%但合約負債4年最低，2026Q1增量僅1.56億(低基期)。69.8x PE未反映訂單斷層風險。</li><li><strong>風險二：PE極端溢價，安全邊際為負</strong> PE 69.8x為歷史合理區間3-4.6倍。樂觀情境EPS 4.32元x22x=95元=現價(無安全邊際)。若EPS僅2-2.5元，合理價30-47元(下行50-68%)。</li><li><strong>風險三：「結構性改善」誤判爲「成長翻轉」</strong> 本輪復甦為去庫存反彈(FY22存貨228天→FY25 139天)，非需求好轉。漢錸出售4億缺口未補。</li></ul><p><strong>綜合評定</strong>：東捷屬「便宜的理由(景氣週期上升)」非「壞掉的真相」。轉型方向正確、資產負債安全(淨現金19億)。但股價已完全反映雙重預期，欠缺安全邊際。結論：未來可期，買點需等待。</p><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>PE/估值數據</strong>：HiStock歷史PE區間(6.23x low/15-22x mid/69.8x current)；WantGoo P/B 4.86x、每股淨值19.54元；法人報告(玉山證19x PE目標60元、統一投顧目標120元)</li><li><strong>股價/籌碼數據</strong>：CMoney/鉅亨/玩股網收盤94.9元(4/29)；融資10,616張(4/28)；外資4月淨賣超6,379張；投信0持股；千張大戶44.48%</li><li><strong>年報篩選</strong>：OK — F01-F17所有基礎數據均來自2023/Q4/2024/Q4/2025/Q4合併財報原始數據，此處為跨17份報告的整合性二階分析</li><li><strong>營收預估</strong>：2026Q1實際6.73億(YoY+30%)來自公開資訊觀測站月營收公告；2026全年EPS共識來自玉山投顧(3.16元)/市場樂觀推估(4-5元)</li><li><strong>PE河流圖推斷</strong>：歷史PE區間來自HiStock十年圖表；股價超越+2SD為基於河流圖視覺化標準差判讀</li><li><strong>關鍵核對碼</strong>： <ul><li><code>2025 EPS = 266,821K / 164,818K = 1.36元</code> ✓（年報P.9）</li><li><code>Current PE = 94.9 / 1.36 = 69.78x</code></li><li><code>Forward PE(consensus) = 94.9 / 3.16 = 30.03x</code></li><li><code>PB = 94.9 / 19.54 = 4.86x</code></li><li><code>BEP = 23.2億(F10推算) / Margin of Safety = (28.7-23.2)/28.7 = 19.2%</code></li><li><code>2025 Peak Div = 1.1元 / Payout 80.7%</code> (F13)</li><li><code>合約負債798M / 能見度101天</code> (F03)</li></ul></li></ul><hr><p><em>報告生成時間：2026-04-30 00:10（GMT+8）</em><em>審計師：投資研究員 (finance-investment-researcher)</em><em>整合來源：F01-F17共17份財務組審計報告 + 即時市場估值數據</em></p>',22)])])}const u=e(l,[["render",n]]);export{P as __pageData,u as default};
